mapper.select:
SELECT id, name, model, serial_number, manufacturer, manufacture_date, max_altitude, max_speed, weight, status, description, created_at, updated_at
FROM uavs
WHERE id = #{id}

SELECT id, name, model, serial_number, manufacturer, manufacture_date, max_altitude, max_speed, weight, status, description, created_at, updated_at
FROM uavs
WHERE serial_number = #{serialNumber}

SELECT id, name, model, serial_number, manufacturer, manufacture_date, max_altitude, max_speed, weight, status, description, created_at, updated_at FROM uavs WHERE 1=1
AND name LIKE '%' || #{name} || '%'
AND model LIKE '%' || #{model} || '%'
AND serial_number LIKE '%' || #{serialNumber} || '%'
AND status = #{status}
ORDER BY id DESC LIMIT #{limit} OFFSET #{offset}
